import { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import api from "../services/api";
import PostItem from "../components/PostItem";
import toast from "react-hot-toast";

export default function Dashboard() {

  const [items, setItems] = useState([]);
  const [loading, setLoading] = useState(true);

  const [search, setSearch] = useState("");
  const [filterType, setFilterType] = useState("");

  const loadItems = async () => {

    try {

      const res = await api.get("/items");
      setItems(res.data);

    } catch {

      toast.error("Failed to load items");

    } finally {

      setLoading(false);

    }

  };

  useEffect(() => {
    loadItems();
  }, []);

  const getImageUrl = (path) => {
    if (!path) return null;
    return `http://localhost:5000${path}`;
  };

  /* ================= FILTER ITEMS ================= */

  const filteredItems = items.filter(item => {

    const matchSearch =
      !search ||
      item.title?.toLowerCase().includes(search.toLowerCase());

    const matchType =
      !filterType || item.type === filterType;

    return matchSearch && matchType;

  });

  /* ================= STATS ================= */

  const totalItems = items.length;
  const lostItems = items.filter(i => i.type === "lost").length;
  const foundItems = items.filter(i => i.type === "found").length;
  const returnedItems = items.filter(i => i.status === "returned").length;

  if (loading) {
    return <div className="p-10 text-center">Loading dashboard...</div>;
  }

  return (

    <div className="min-h-screen p-6 bg-gray-50">

      {/* PAGE TITLE */}

      <h1 className="text-3xl font-bold mb-6">
        Lost & Found Dashboard
      </h1>


      {/* ================= STATS ================= */}

      <div className="grid md:grid-cols-4 gap-4 mb-8">

        <StatCard title="Total Items" value={totalItems} />
        <StatCard title="Lost Items" value={lostItems} />
        <StatCard title="Found Items" value={foundItems} />
        <StatCard title="Returned Items" value={returnedItems} />

      </div>


      {/* ================= POST ITEM ================= */}

      <PostItem onPosted={loadItems} />


      {/* ================= SEARCH + FILTER ================= */}

      <div className="flex flex-wrap gap-3 items-center mt-8">

        <input
          type="text"
          placeholder="Search items..."
          value={search}
          onChange={(e)=>setSearch(e.target.value)}
          className="border p-2 rounded-lg w-64"
        />

        <select
          value={filterType}
          onChange={(e)=>setFilterType(e.target.value)}
          className="border p-2 rounded-lg"
        >
          <option value="">All Items</option>
          <option value="lost">Lost</option>
          <option value="found">Found</option>
        </select>

      </div>


      {/* ================= ITEMS GRID ================= */}

      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 mt-6">

        {filteredItems.length === 0 && (

          <div className="col-span-full text-center text-gray-500 mt-10">
            No items found
          </div>

        )}

        {filteredItems.map(item => {

          const image =
            item.images?.length > 0
              ? getImageUrl(item.images[0])
              : null;

          return (

            <div
              key={item._id}
              className="bg-white rounded-xl shadow hover:shadow-lg transition p-4"
            >

              {image && (

                <img
                  src={image}
                  className="h-40 w-full object-cover mb-3 rounded"
                />

              )}

              <div className="flex justify-between items-center">

                <h2 className="font-bold text-lg">
                  {item.title}
                </h2>

                <span
                  className={`text-xs px-2 py-1 rounded
                  ${
                    item.type === "lost"
                      ? "bg-red-100 text-red-700"
                      : "bg-green-100 text-green-700"
                  }`}
                >
                  {item.type?.toUpperCase()}
                </span>

              </div>

              <p className="text-sm text-gray-500">
                {item.category}
              </p>

              <p className="text-sm mt-2 text-gray-700">
                {item.description}
              </p>

              <Link
                to={`/items/${item._id}`}
                className="block mt-4 bg-blue-600 text-white text-center py-2 rounded hover:bg-blue-700"
              >
                View Details
              </Link>

            </div>

          );

        })}

      </div>

    </div>

  );

}


/* ================= STAT CARD ================= */

function StatCard({ title, value }) {

  return (

    <div className="bg-white p-5 rounded-xl shadow text-center">

      <p className="text-gray-500 text-sm">
        {title}
      </p>

      <p className="text-3xl font-bold mt-1">
        {value}
      </p>

    </div>

  );

}
